import React, { useEffect, useState, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Plus, X, Tag, Palette, Edit2, Target, Loader2, 
  ChevronLeft, ChevronRight, TrendingDown, DollarSign, Star, Trash2 
} from 'lucide-react';
import '../styles/CategoriasMetas.css'; // Reutilizando a base de estilos

const CategoriasMetas = () => {
  const [loading, setLoading] = useState(true);
  const [categorias, setCategorias] = useState([]);
  const [metasMes, setMetasMes] = useState([]);
  const [activeTab, setActiveTab] = useState('despesa'); // 'despesa', 'provento', 'pessoal'
  
  // Controle de Período
  const [mes, setMes] = useState(new Date().getMonth() + 1);
  const [ano, setAno] = useState(new Date().getFullYear());

  // Controle de Modal
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);
  
  const [form, setForm] = useState({ 
    nome: '', 
    cor: '#4361ee', 
    valor_meta: '' 
  });

  useEffect(() => {
    buscarDados();
  }, [mes, ano]);

  async function buscarDados() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const [resCats, resMetas] = await Promise.all([
        supabase.from('categorias').select('*').order('nome'),
        supabase.from('metas')
          .select(`*, categorias(nome, cor, id)`)
          .eq('mes_referencia', mes)
          .eq('ano_referencia', ano)
      ]);

      setCategorias(resCats.data || []);
      setMetasMes(resMetas.data || []);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setLoading(false);
    }
  }

  const openModal = (item = null) => {
    if (item) {
      // Se for aba pessoal, o item já é a meta. Se não, buscamos a meta associada à categoria.
      const metaExistente = activeTab === 'pessoal' 
        ? item 
        : metasMes.find(m => m.categoria_id === item.id);
      
      setEditMode(true);
      setSelectedItem(item);
      setForm({ 
        nome: activeTab === 'pessoal' ? item.nome_meta_pessoal : item.nome, 
        cor: activeTab === 'pessoal' ? '#8b5cf6' : item.cor, 
        valor_meta: metaExistente ? metaExistente.valor_meta : '' 
      });
    } else {
      setEditMode(false);
      setSelectedItem(null);
      setForm({ nome: '', cor: '#4361ee', valor_meta: '' });
    }
    setShowModal(true);
  };

  async function handleSalvar(e) {
    e.preventDefault();
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      let categoriaId = activeTab !== 'pessoal' ? selectedItem?.id : null;

      // 1. Lógica para Categorias Normais (Gastos/Receitas)
      if (activeTab !== 'pessoal') {
        const catPayload = { 
          user_id: user.id, 
          nome: form.nome, 
          tipo: activeTab, 
          cor: form.cor 
        };

        if (editMode && categoriaId) {
          await supabase.from('categorias').update(catPayload).eq('id', categoriaId);
        } else {
          const { data: newCat, error: catErr } = await supabase
            .from('categorias')
            .insert([catPayload])
            .select().single();
          if (catErr) throw catErr;
          categoriaId = newCat.id;
        }
      }

      // 2. Lógica para Metas (Incluindo Objetivos Pessoais)
      if (activeTab === 'pessoal' && !editMode) {
        // Criar categoria fantasma para objetivo pessoal
        const { data: newCat } = await supabase
          .from('categorias')
          .insert({ nome: form.nome, tipo: 'passoal', cor: '#8b5cf6', user_id: user.id })
          .select().single();
        
        await supabase.from('metas').insert({
          user_id: user.id,
          categoria_id: newCat.id,
          valor_meta: parseFloat(form.valor_meta) || 0,
          tipo_meta: 'pessoal',
          mes_referencia: mes,
          ano_referencia: ano,
          nome_meta_pessoal: form.nome
        });
      } else {
        // Upsert de meta para categorias normais ou edição de pessoal
        const metaPayload = {
          user_id: user.id,
          categoria_id: activeTab === 'pessoal' ? selectedItem.categoria_id : categoriaId,
          valor_meta: parseFloat(form.valor_meta) || 0,
          tipo_meta: activeTab,
          mes_referencia: mes,
          ano_referencia: ano
        };

        if (activeTab === 'pessoal') metaPayload.nome_meta_pessoal = form.nome;

        await supabase.from('metas').upsert(metaPayload, { 
          onConflict: 'categoria_id, mes_referencia, ano_referencia' 
        });
      }

      setShowModal(false);
      buscarDados();
    } catch (error) {
      alert("Erro ao salvar: " + error.message);
    } finally {
      setLoading(false);
    }
  }

  async function excluirRegistro() {
    const confirmMsg = activeTab === 'pessoal' 
      ? `Excluir objetivo "${form.nome}"?`
      : `Excluir categoria "${form.nome}" e todas as suas metas associadas?`;

    if (window.confirm(confirmMsg)) {
      try {
        if (activeTab === 'pessoal') {
          await supabase.from('metas').delete().eq('id', selectedItem.id);
        } else {
          await supabase.from('categorias').delete().eq('id', selectedItem.id);
        }
        setShowModal(false);
        buscarDados();
      } catch (error) {
        console.error("Erro ao excluir:", error);
      }
    }
  }

  const itemsFiltrados = useMemo(() => {
    if (activeTab === 'pessoal') {
      return metasMes.filter(m => m.tipo_meta === 'pessoal');
    }
    return categorias.filter(c => c.tipo === activeTab);
  }, [categorias, metasMes, activeTab]);

  const formatCurrency = (val) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val || 0);
  };

  return (
    <div className="cat-page-wrapper metas-container">
      {/* FAB Button */}
      <button className="cat-fab" onClick={() => openModal()} title="Novo">
        <Plus size={30} />
      </button>

      {/* Header Unificado */}
      <header className="metas-header">
        <div className="cat-title-area">
          <div className="titulo-secao">
            <Target size={28} color="#4361ee" />
            <h1>Planejamento</h1>
          </div>
          <p>Gerencie categorias e metas mensais</p>
        </div>
        
        <div className="seletor-periodo">
          <button onClick={() => setMes(m => m === 1 ? 12 : m - 1)}><ChevronLeft size={20}/></button>
          <span>
            {new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date(ano, mes - 1))} {ano}
          </span>
          <button onClick={() => setMes(m => m === 12 ? 1 : m + 1)}><ChevronRight size={20}/></button>
        </div>
      </header>

      {/* Tabs Estilizadas */}
      <nav className="metas-tabs">
        <button className={activeTab === 'despesa' ? 'active' : ''} onClick={() => setActiveTab('despesa')}>
          <TrendingDown size={18} /> Gastos
        </button>
        <button className={activeTab === 'provento' ? 'active' : ''} onClick={() => setActiveTab('provento')}>
          <DollarSign size={18} /> Receitas
        </button>
        <button className={activeTab === 'pessoal' ? 'active' : ''} onClick={() => setActiveTab('pessoal')}>
          <Star size={18} /> Objetivos
        </button>
      </nav>

      {/* Lista de Itens */}
      <div className="cat-list-container metas-content">
        {loading ? (
          <div className="cat-status"><Loader2 className="spinner" /> Sincronizando dados...</div>
        ) : itemsFiltrados.length > 0 ? (
          <div className={activeTab === 'pessoal' ? "metas-pessoais-list" : "grid-metas-cats"}>
            {itemsFiltrados.map(item => {
              const meta = activeTab === 'pessoal' ? item : metasMes.find(m => m.categoria_id === item.id);
              const cor = activeTab === 'pessoal' ? '#8b5cf6' : item.cor;
              const nome = activeTab === 'pessoal' ? item.nome_meta_pessoal : item.nome;

              return (
                <div key={item.id} className="cat-item-row" onClick={() => openModal(item)}>
                  <div className="cat-item-main">
                    <div className="cat-status-dot" style={{ backgroundColor: cor }}></div>
                    <div className="cat-info-text">
                      <span className="cat-item-name" style={{ color: cor }}>{nome}</span>
                      <span className="cat-item-meta">
                        Planejado: <strong>{formatCurrency(meta?.valor_meta)}</strong>
                      </span>
                    </div>
                  </div>
                  <Edit2 size={16} className="cat-edit-icon" />
                </div>
              );
            })}
          </div>
        ) : (
          <div className="cat-empty">Nenhum registro encontrado nesta categoria.</div>
        )}
      </div>

      {/* Modal Unificado */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="cat-modal fade-in" onClick={e => e.stopPropagation()}>
            <div className="cat-modal-header">
              <h3>{editMode ? 'Editar' : 'Novo'} {activeTab === 'pessoal' ? 'Objetivo' : 'Categoria'}</h3>
              <button onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>

            <form onSubmit={handleSalvar} className="cat-modal-form">
              <div className="cat-input-box">
                <label><Tag size={14}/> Nome</label>
                <input 
                  type="text" required value={form.nome} 
                  onChange={e => setForm({...form, nome: e.target.value})} 
                  placeholder="Ex: Alimentação, Viagem..."
                />
              </div>

              <div className="cat-input-box">
                <label><Target size={14}/> Valor da Meta</label>
                <div className="cat-money-input-wrapper">
                  <span className="prefix">R$</span>
                  <input 
                    type="number" step="0.01" required
                    value={form.valor_meta} 
                    onChange={e => setForm({...form, valor_meta: e.target.value})} 
                    placeholder="0,00"
                  />
                </div>
              </div>
              
              {activeTab !== 'pessoal' && (
                <div className="cat-input-box">
                  <label><Palette size={14}/> Cor de Identificação</label>
                  <div className="cat-color-picker-container">
                    <input type="color" className="cat-color-input" value={form.cor} onChange={e => setForm({...form, cor: e.target.value})} />
                    <input type="text" className="cat-hex-input" value={form.cor.toUpperCase()} onChange={e => setForm({...form, cor: e.target.value})} maxLength={7} />
                  </div>
                </div>
              )}

              <div className="cat-modal-actions">
                {editMode && (
                  <button type="button" className="btn-cat-delete" onClick={excluirRegistro}>
                    <Trash2 size={20} />
                  </button>
                )}
                <button type="submit" className="btn-cat-save" disabled={loading}>
                  {loading ? 'Processando...' : editMode ? 'Salvar Alterações' : 'Criar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoriasMetas;
